-- ═══════════════════════════════════════════════════════════════════════════
-- Migration 130 : Fix category_id NULL pour les produits importés en 128
-- 
-- La 128 mappait vers les slugs des migrations historiques (pains, patisseries,
-- gateaux...) qui ont été remplacés dans la DB par les UPPERCASE matching Excel.
-- Cette migration rattache les ~108 produits orphelins à la bonne catégorie en
-- se basant sur leur nom (et donc leur catégorie Excel d'origine).
-- ═══════════════════════════════════════════════════════════════════════════

BEGIN;

-- ─── baguette (6 produits) ───
UPDATE products SET category_id = (SELECT id FROM categories WHERE slug = 'baguette')
WHERE category_id IS NULL AND name IN ('BAGUETTE COMPLÈTE', 'BAGUETTE NORMALE', 'BAGUETTE NORMALE 1,25', 'BAGUETTE NORMALE FARINE', 'BAGUETTE NORMALE SÉSAME', 'BAGUETTE SEMOULE');

