-- ─── Produits sans catégorie Excel (NaN) — inférence par produit similaire ───
UPDATE products SET category_id = (SELECT id FROM categories WHERE slug = 'patisserie-premium')
WHERE category_id IS NULL AND name IN ('FEUILLE D''AUTOMNE', 'OFAURIA 6 PERSONNES');
UPDATE products SET category_id = (SELECT id FROM categories WHERE slug = 'pieces-portions')
WHERE category_id IS NULL AND name IN ('MUFFIN CHOCOLAT', 'MUFFIN VANILLE');

-- Garde-fou : alerte si des produits restent sans catégorie
DO $$
DECLARE orphans INT;
BEGIN
  SELECT COUNT(*) INTO orphans FROM products WHERE category_id IS NULL;
  IF orphans > 0 THEN
    RAISE WARNING '% produit(s) restent sans catégorie après cleanup', orphans;
  END IF;
END $$;

COMMIT;